import Fuse, { type IFuseOptions, type FuseResultMatch } from "fuse.js";

// ── Types ───────────────────────────────────────────────────
export interface SearchResult<T> {
  item: T;
  matches: readonly FuseResultMatch[] | undefined;
}

// ── Fuse.js powered search ──────────────────────────────────

/**
 * Create a fuzzy search function for a static dataset.
 * Returns results ranked by relevance with match metadata for highlighting.
 */
export function createSearch<T>(
  items: readonly T[],
  options: IFuseOptions<T>,
): (query: string) => SearchResult<T>[] {
  const fuse = new Fuse([...items], { ...options, includeMatches: true });

  return (query: string): SearchResult<T>[] => {
    if (!query.trim()) {
      return items.map((item) => ({ item, matches: undefined }));
    }
    return fuse.search(query).map((r) => ({
      item: r.item,
      matches: r.matches,
    }));
  };
}

