// ── Relaxed search for "Did you mean?" suggestions ──────────

export function createRelaxedSearch<T>(
  items: readonly T[],
  options: IFuseOptions<T>,
): (query: string, limit?: number) => T[] {
  const fuse = new Fuse([...items], {
    ...options,
    threshold: 0.6,
    includeMatches: false,
  });

  return (query: string, limit = 3): T[] => {
    if (!query.trim()) return [];
    return fuse
      .search(query, { limit })
      .map((r) => r.item);
  };
}
